from prometheus_client import start_http_server, Gauge
import os
import time
import psycopg2
from psycopg2 import OperationalError

def get_db_connection():
    try:
        conn = psycopg2.connect(
            dbname=os.getenv('DB_NAME'),
            user=os.getenv('DB_USER'),
            password=os.getenv('DB_PASSWORD'),
            host=os.getenv('DB_HOST'),
            port=os.getenv('DB_PORT')
        )
        return conn
    except OperationalError:
        return None

def check_db_connection():
    conn = get_db_connection()
    if conn:
        conn.close()
        return 1
    return 0

def main():
    db_health_gauge = Gauge('db_connection_health', 'Database connection health',
                            ['username', 'host', 'connection_string'])

    start_http_server(8000)

    while True:
        db_user = os.getenv('DB_USER', 'unknown')
        db_host = os.getenv('DB_HOST', 'unknown')
        connection_string = f"{db_user}@{db_host}"
        
        db_health = check_db_connection()
        db_health_gauge.labels(username=db_user, host=db_host, connection_string=connection_string).set(db_health)
        
        time.sleep(10)

if __name__ == '__main__':
    main()